#include <stdio.h>
#include <stdlib.h>

int countDigit(int num, int digit) {
    int count = 0;
    while (num > 0) {
        if (num % 10 == digit) {
            count++;
        }
        num /= 10;
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, C, D;
        scanf("%d %d %d %d", &A, &B, &C, &D);
        int brotherMax = -1, sisterMax = -1;
        int brotherNum = -1, sisterNum = -1;
        for (int i = A; i <= B; i++) {
            int brotherCount = countDigit(i, C);
            int sisterCount = countDigit(i, D);
            if (brotherCount > brotherMax) {
                brotherMax = brotherCount;
                brotherNum = i;
            }
            if (sisterCount > sisterMax) {
                sisterMax = sisterCount;
                sisterNum = i;
            }
        }
        int chefNum = -1;
        double maxProb = 0.0;
        for (int i = A; i <= B; i++) {
            double prob = 0.0;
            if (i == brotherNum && i == sisterNum) {
                prob = 1.0 / 3.0;
            } else if (i == brotherNum || i == sisterNum) {
                prob = 1.0 / 2.0;
            } else {
                prob = 1.0;
            }
            if (prob > maxProb) {
                maxProb = prob;
                chefNum = i;
            }
        }
        printf("%d\n", chefNum);
    }
    return 0;
}

